jQuery(document).ready(function($){var $rippleBox=$('#solutionRipple');if($rippleBox.length&&$.fn.ripples){try{$rippleBox.ripples({resolution:512,dropRadius:28,perturbance:.09,interactive:true});setInterval(function(){var x=Math.random()*$rippleBox.outerWidth();var y=Math.random()*$rippleBox.outerHeight();$rippleBox.ripples('drop',x,y,30,.12)},1600)}catch(e){console.log(e)}}});document.addEventListener("DOMContentLoaded",function(){const cards=document.querySelectorAll(".solution-card");const observer=new IntersectionObserver(function(entries){entries.forEach(function(entry){if(entry.isIntersecting){entry.target.classList.add("is-show")}})},{threshold:.18});cards.forEach(function(card){observer.observe(card)})});